// DrawerMoleculeImpl.tsx — JONA Implementation
import React, { useEffect } from 'react';
import { InterDrawerMolecule, DRAWER_MOLECULE_DEFAULTS } from './InterDrawerMolecule';
import { DrawerMoleculeView } from './DrawerMoleculeView';

export const DrawerMoleculeImpl: React.FC<InterDrawerMolecule> = (props) => {
  const merged = { ...DRAWER_MOLECULE_DEFAULTS, ...props };

  useEffect(() => {
    if (!merged.open) return;
    const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape') props.onClose(); };
    document.addEventListener('keydown', onKey);
    document.body.style.overflow = 'hidden';
    return () => {
      document.removeEventListener('keydown', onKey);
      document.body.style.overflow = '';
    };
  }, [merged.open, props.onClose]);

  return (
    <DrawerMoleculeView
      open={merged.open}
      side={merged.side}
      size={merged.size}
      showCloseButton={merged.showCloseButton}
      title={props.title}
      description={props.description}
      className={props.className}
      footer={props.footer}
      onClose={props.onClose}
      onOverlayClick={props.onClose}
    >
      {props.children}
    </DrawerMoleculeView>
  );
};

DrawerMoleculeImpl.displayName = 'DrawerMolecule';
